




import { useEffect, useRef, useState } from "react";

const CAMPUS_MAP_SRC = "data:image/png;base64,";

// ── Camera → Zone mapping ──────────────────────────────────────────
// Edit this to match your actual camera IDs from the Python backend
const CAM_ZONE_MAP = {
  cam1: "entrance",   // cam1 in Python CAMERAS dict
  cam2: "lhtc",       // cam2 in Python CAMERAS dict
  cam3: "cc",
  cam4: "sac",
  cam5: "h1",
  cam6: "admin",
  cam7: "cl",
  cam8: "oat",
};

const CAMPUS_ZONES = [
  { id: "entrance", label: "Entrance", x: 0.11, y: 0.55 },
  { id: "admin",    label: "Admin",    x: 0.14, y: 0.19 },
  { id: "cl",       label: "CL",       x: 0.37, y: 0.52 },
  { id: "hex",      label: "Hex",      x: 0.47, y: 0.62 },
  { id: "lhtc",     label: "LHTC",     x: 0.57, y: 0.44 },
  { id: "cc",       label: "CC",       x: 0.73, y: 0.07 },
  { id: "oat",      label: "OAT",      x: 0.82, y: 0.63 },
  { id: "sac",      label: "SAC",      x: 0.93, y: 0.71 },
  { id: "h1",       label: "H1",       x: 0.57, y: 0.85 },
  { id: "atm",      label: "ATM",      x: 0.27, y: 0.68 },
];

const DENSITY_RGB = {
  LOW:    [0,   220, 70 ],
  MEDIUM: [255, 150, 0  ],
  HIGH:   [255, 20,  20 ],
};

const DENSITY_HEX = {
  LOW:    "#00dc46",
  MEDIUM: "#ff9600",
  HIGH:   "#ff1414",
};

function splatPixels(imgData, W, H, cx, cy, radius, r, g, b, alpha) {
  const px = imgData.data;
  const r2 = radius * radius;
  const x0 = Math.max(0, Math.floor(cx - radius * 3));
  const x1 = Math.min(W - 1, Math.ceil(cx  + radius * 3));
  const y0 = Math.max(0, Math.floor(cy - radius * 3));
  const y1 = Math.min(H - 1, Math.ceil(cy  + radius * 3));
  for (let y = y0; y <= y1; y++) {
    for (let x = x0; x <= x1; x++) {
      const dx = x - cx, dy = y - cy;
      const val = alpha * Math.exp(-(dx*dx + dy*dy) / (2*r2));
      if (val < 0.01) continue;
      const idx = (y * W + x) * 4;
      const prevA = px[idx+3] / 255;
      const newA  = val + prevA * (1 - val);
      if (newA < 0.001) continue;
      px[idx  ] = Math.round((r*val + px[idx  ]*prevA*(1-val)) / newA);
      px[idx+1] = Math.round((g*val + px[idx+1]*prevA*(1-val)) / newA);
      px[idx+2] = Math.round((b*val + px[idx+2]*prevA*(1-val)) / newA);
      px[idx+3] = Math.round(newA * 255);
    }
  }
}

export default function CrowdHeatmap({ latestStat, cameraId, liveStates }) {
  const containerRef  = useRef(null);
  const bgCanvasRef   = useRef(null);
  const heatCanvasRef = useRef(null);
  const animRef       = useRef(null);
  const [size, setSize] = useState({ w: 800, h: 456 });

  // ── Resize ──────────────────────────────────────────────────────
  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const obs = new ResizeObserver((entries) => {
      const { width } = entries[0].contentRect;
      setSize({ w: Math.round(width), h: Math.round(width * 0.57) });
    });
    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  // ── Draw map background ─────────────────────────────────────────
  useEffect(() => {
    const bg = bgCanvasRef.current;
    if (!bg) return;
    bg.width  = size.w;
    bg.height = size.h;
    const ctx = bg.getContext("2d");
    const img = new Image();
    img.onload = () => ctx.drawImage(img, 0, 0, size.w, size.h);
    img.src = CAMPUS_MAP_SRC;
  }, [size]);

  // ── Build zone data from liveStates only (no stale global state) ──
  // This ensures exactly one blob per active camera, no extras
  const getZoneData = () => {
    const result = {};
    if (!liveStates) return result;
    Object.entries(liveStates).forEach(([camId, data]) => {
      if (!data) return;
      const zoneId = CAM_ZONE_MAP[camId];
      if (!zoneId) return;
      const density = (data.density || "LOW").toUpperCase();
      const people  = data.people  || 0;
      const ratio   = data.densityRatio || 0;
      result[zoneId] = { density, people, ratio, camId };
    });
    return result;
  };

  // ── Heat animation loop ─────────────────────────────────────────
  useEffect(() => {
    const hc = heatCanvasRef.current;
    if (!hc) return;
    hc.width  = size.w;
    hc.height = size.h;
    const ctx = hc.getContext("2d");

    const render = () => {
      const W = size.w, H = size.h;
      // Fresh zone data every frame — derived from liveStates
      const zoneData = getZoneData();

      ctx.clearRect(0, 0, W, H);
      const imgData = ctx.createImageData(W, H);

      CAMPUS_ZONES.forEach(zone => {
        const st = zoneData[zone.id];
        if (!st || st.people === 0) return;

        const rgb = DENSITY_RGB[st.density] || DENSITY_RGB.LOW;
        const [r, g, b] = rgb;
        const cx = zone.x * W;
        const cy = zone.y * H;
        const radius = 0.11 * W;
        const intensity = Math.min(0.92, 0.60 + (st.ratio || 0) * 0.32);

        splatPixels(imgData, W, H, cx, cy, radius, r, g, b, intensity);

        const sats = Math.min(3, Math.floor(st.people / 4));
        for (let i = 0; i < sats; i++) {
          const angle = (i / Math.max(sats, 1)) * 2 * Math.PI + zone.x * 5;
          const dist  = radius * 0.52;
          splatPixels(imgData, W, H,
            cx + Math.cos(angle) * dist,
            cy + Math.sin(angle) * dist,
            radius * 0.58, r, g, b, intensity * 0.42);
        }
      });

      ctx.putImageData(imgData, 0, 0);
      ctx.filter = "blur(13px)";
      ctx.drawImage(hc, 0, 0);
      ctx.filter = "none";

      // Pulse rings on MEDIUM / HIGH zones
      CAMPUS_ZONES.forEach(zone => {
        const st = zoneData[zone.id];
        if (!st || st.people === 0 || st.density === "LOW") return;
        const [r_, g_, b_] = DENSITY_RGB[st.density];
        const px_ = zone.x * W, py_ = zone.y * H;
        const t   = (Date.now() % 1500) / 1500;
        ctx.strokeStyle = `rgba(${r_},${g_},${b_},${(0.9 - t*0.85).toFixed(2)})`;
        ctx.lineWidth   = 2.5;
        ctx.beginPath();
        ctx.arc(px_, py_, 14 + t*22, 0, 2*Math.PI);
        ctx.stroke();
      });

      animRef.current = requestAnimationFrame(render);
    };

    animRef.current = requestAnimationFrame(render);
    return () => cancelAnimationFrame(animRef.current);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [size, liveStates]);

  // Active zones for labels/legend — only from cameras in liveStates
  const zoneData = getZoneData();
  const activeZones = CAMPUS_ZONES
    .map(z => ({ ...z, st: zoneData[z.id] }))
    .filter(z => z.st && z.st.people > 0);

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:8 }}>

      <div ref={containerRef} style={{
        position:"relative", width:"100%",
        borderRadius:10, overflow:"hidden",
        boxShadow:"0 4px 20px rgba(0,0,0,0.3)",
      }}>

        {/* Map layer */}
        <canvas ref={bgCanvasRef} width={size.w} height={size.h}
          style={{ display:"block", width:"100%", height:"auto" }} />

        {/* Heat overlay */}
        <canvas ref={heatCanvasRef} width={size.w} height={size.h}
          style={{
            position:"absolute", top:0, left:0,
            width:"100%", height:"auto",
            mixBlendMode:"normal", opacity:0.65,
            pointerEvents:"none",
          }} />

        {/* LIVE badge */}
        <div style={{
          position:"absolute", top:8, right:8,
          background:"rgba(8,18,40,0.88)",
          color:"#4ade80", fontSize:10,
          fontFamily:"monospace",
          padding:"3px 10px", borderRadius:99,
          border:"1px solid rgba(74,222,128,0.35)",
          display:"flex", alignItems:"center", gap:6,
        }}>
          <span style={{
            width:6, height:6, borderRadius:"50%",
            background:"#4ade80", boxShadow:"0 0 6px #4ade80",
            display:"inline-block",
            animation:"hmlp 1.2s ease-in-out infinite",
          }} />
          LIVE DENSITY
        </div>

        {/* One label per active zone */}
        {activeZones.map(zone => (
          <div key={zone.id} style={{
            position:"absolute",
            left:`${zone.x * 100}%`,
            top:`${zone.y * 100}%`,
            transform:"translate(-50%, -130%)",
            background:`${DENSITY_HEX[zone.st.density]}22`,
            border:`1.5px solid ${DENSITY_HEX[zone.st.density]}`,
            color: DENSITY_HEX[zone.st.density],
            fontSize:9, fontFamily:"monospace", fontWeight:700,
            padding:"2px 7px", borderRadius:5,
            whiteSpace:"nowrap",
            boxShadow:`0 0 8px ${DENSITY_HEX[zone.st.density]}55`,
            pointerEvents:"none",
          }}>
            {zone.label}
            <span style={{ opacity:0.8, marginLeft:4 }}>
              {zone.st.density}
            </span>
          </div>
        ))}
      </div>

      {/* Legend */}
      <div style={{
        display:"flex", alignItems:"center", flexWrap:"wrap", gap:10,
        fontSize:10, fontFamily:"monospace", color:"#64748b",
      }}>
        {["LOW","MEDIUM","HIGH"].map(lvl => (
          <div key={lvl} style={{ display:"flex", alignItems:"center", gap:4 }}>
            <div style={{
              width:11, height:11, borderRadius:3,
              background: DENSITY_HEX[lvl],
              boxShadow:`0 0 5px ${DENSITY_HEX[lvl]}`,
            }} />
            <span>{lvl}</span>
          </div>
        ))}
        <div style={{ flex:1 }} />
        {activeZones.map(zone => (
          <span key={zone.id} style={{
            color: DENSITY_HEX[zone.st.density],
            background:`${DENSITY_HEX[zone.st.density]}15`,
            border:`1px solid ${DENSITY_HEX[zone.st.density]}44`,
            padding:"2px 8px", borderRadius:99,
          }}>
            {zone.label}: {zone.st.density} · {zone.st.people}p
          </span>
        ))}
      </div>

      <style>{`@keyframes hmlp { 0%,100%{opacity:1} 50%{opacity:0.2} }`}</style>
    </div>
  );
}